  const _origText=new WeakMap();
  const _origAttrs=new WeakMap();
  function _translateNode(node,toEnglish){
    if(node.nodeType===Node.TEXT_NODE){
      const raw=node.nodeValue||'';const key=raw.trim();if(!key)return;
      if(toEnglish){const val=FULL_TRANSLATIONS[key];if(val&&val!==key){if(!_origText.has(node))_origText.set(node,raw);node.nodeValue=raw.replace(key,val);}}
      else if(_origText.has(node)){node.nodeValue=_origText.get(node);}
      return;
    }
    if(node.nodeType!==Node.ELEMENT_NODE)return;
    if(['SCRIPT','STYLE','NOSCRIPT'].includes(node.tagName))return;
    const attrs=['aria-label','title','placeholder','alt'];
    attrs.forEach(attr=>{const raw=node.getAttribute?.(attr);if(!raw)return;const key=raw.trim();if(toEnglish){const val=FULL_TRANSLATIONS[key];if(val&&val!==key){let saved=_origAttrs.get(node)||{};if(!(attr in saved))saved[attr]=raw;_origAttrs.set(node,saved);node.setAttribute(attr,raw.replace(key,val));}}else{const saved=_origAttrs.get(node);if(saved&&attr in saved)node.setAttribute(attr,saved[attr]);}});
    [...node.childNodes].forEach(ch=>_translateNode(ch,toEnglish));
  }
  function applyFullTranslation(toEnglish,root=document.documentElement){_translateNode(root,toEnglish);}

  Object.assign(FULL_TRANSLATIONS,{"Решения и кейсы":"Solutions and cases","Аналитическое агентство Unitmetra":"Unitmetra analytics agency","Кейсы и решения, которые команда Unitmetra может реализовать для вашего бизнеса":"Cases and solutions the Unitmetra team can deliver for your business","Берём задачу под ключ: проверяем данные, проводим анализ, строим прогнозы и переводим результат в понятный план действий. Под каждый проект подключаем команду опытных профильных аналитиков, ML-специалистов и экспертов по автоматизации.":"We take the task end to end: validate data, analyse it, build forecasts and turn the result into a clear action plan. Each project is staffed with experienced specialist analysts, ML specialists and automation experts.","Обсудить задачу":"Discuss the task","Посмотреть решения":"View solutions","Профильная команда":"Specialised team","Подбираем опытных специалистов под бизнес-задачу":"We assign experienced specialists to the business problem","Контроль качества":"Quality control","Проверяем расчёты и выводы перед передачей":"We review calculations and findings before delivery","Единая ответственность":"Single point of responsibility","Один проект, согласованный результат и сроки":"One project, agreed deliverables and timeline","Понятный язык":"Clear language","Без перегруза терминами и лишних метрик":"No overload with jargon or irrelevant metrics","ФЛАГМАНСКИЙ ФОРМАТ ДЛЯ МАРКЕТПЛЕЙСОВ":"FLAGSHIP FORMAT FOR MARKETPLACES","Находим, какие товары создают прибыль, где реклама и возвраты забирают маржу, сколько денег заморожено в остатках и какие действия дадут максимальный эффект.":"We identify which products generate profit, where advertising and returns reduce margin, how much cash is tied up in inventory and which actions can have the greatest impact.","по каждому SKU":"for every SKU","в единой модели":"in one model","план на 30 дней":"30-day plan","Команда":"Team","аналитик + контроль":"analyst + review","Открыть демо-отчёт":"Open demo report","Что входит в отчёт":"What is included in the report","Разделы":"Sections","Юнит-экономика, реклама, возвраты, остатки, прогноз":"Unit economics, advertising, returns, inventory, forecast","Материалы":"Deliverables","Таблицы, интерактивный отчёт, выводы и рекомендации":"Tables, interactive report, findings and recommendations","Приоритетный список действий с объяснением эффекта":"Prioritised action list with impact explanation","Избыток остатков":"Excess inventory","Пример аналитического отчёта":"Analytics report example","Демо-режим · без скачивания":"Demo mode · no download","Маркетплейсы · малый бизнес · Machine Learning":"Marketplaces · small business · Machine Learning","Решения, которые можно заказать в Unitmetra":"Solutions available from Unitmetra","Под каждой задачей можно раскрыть состав результата и открыть интерактивный демо-отчёт. Кнопок скачивания в демо-режиме нет.":"For each task you can expand the deliverables and open an interactive demo report. Demo mode has no download buttons.","Вероятности":"Probabilities","Сегменты":"Segments","Каналы":"Channels","Риск":"Risk","Факторы":"Factors","Удержание":"Retention","Паттерны":"Patterns","Поддержка":"Support","Прибыль":"Profit","Контроль":"Monitoring","Что получит клиент":"What the client receives","В отчёте":"In the report","На выходе":"Delivered result","Факт и прогноз, сезонность, риски дефицита и избытка":"Actuals and forecast, seasonality, shortage and excess risks","Рекомендуемая поставка по SKU и размерам":"Recommended supply by SKU and size","Аналитик по продажам + ML-специалист":"Sales analyst + ML specialist","Вероятность покупки по клиентам и факторы поведения":"Purchase probability by customer and behavioural drivers","Сегменты для коммуникаций и приоритетные аудитории":"Communication segments and priority audiences","Продуктовый аналитик + ML-специалист":"Product analyst + ML specialist","Скоринг риска, факторы снижения и профили сегментов":"Risk scoring, decline drivers and segment profiles","Таблица клиентов и сценарии удержания":"Customer table and retention scenarios","Data Scientist + бизнес-аналитик":"Data Scientist + business analyst","Повторяющиеся формулировки, авторы, временные связи и риск-сигналы":"Recurring wording, authors, temporal links and risk signals","Список отзывов и ID для ручной проверки и поддержки":"Review list and IDs for manual verification and support","Data-аналитик + специалист по качеству данных":"Data analyst + data quality specialist","Выручка, прибыль, расходы, клиенты и эффективность маркетинга":"Revenue, profit, expenses, customers and marketing efficiency","Дашборд собственника и приоритетный план решений":"Owner dashboard and prioritised decision plan","Бизнес-аналитик + специалист по визуализации":"Business analyst + visualisation specialist","Источники, расписание обновлений, контроль ошибок и ключевые KPI":"Sources, update schedule, error monitoring and key KPIs","Рабочий дашборд, документация и регламент обновления":"Production dashboard, documentation and update procedure","Аналитик + Python/SQL-разработчик":"Analyst + Python/SQL developer","Работа как агентство":"Agency delivery model","За проект отвечает не один человек, а согласованная команда":"A coordinated team, not one person, is responsible for the project","Состав специалистов зависит от задачи. Клиент получает единый процесс, контроль качества и понятного ответственного за результат.":"The specialist mix depends on the task. The client gets one process, quality control and a clear person responsible for the result.","Руководитель проекта":"Project lead","Фиксирует задачу, сроки, формат и коммуникацию.":"Defines the task, timeline, format and communication.","Профильный аналитик":"Specialist analyst","Проверяет данные, выполняет расчёты и формирует выводы.":"Validates data, performs calculations and produces findings.","ML / автоматизация":"ML / automation","Подключается, когда нужны прогнозы, код, API или дашборд.":"Joins when forecasting, code, API or dashboards are needed.","Проверяет логику, цифры и понятность рекомендаций.":"Reviews logic, numbers and clarity of recommendations.","Покажите задачу — предложим состав команды и формат результата":"Show us the task — we will propose the team and deliverable format","На созвоне определим, какие данные нужны, что будет в отчёте и какой пакет подойдёт без лишних работ.":"During the call we will define the required data, report contents and the right package without unnecessary work.","Обсудить проект":"Discuss the project","Аналитическое агентство для маркетплейсов и бизнеса: прибыль, прогнозирование, Machine Learning и автоматизация.":"Analytics agency for marketplaces and business: profit, forecasting, Machine Learning and automation.","Интерактивный демо-отчёт":"Interactive demo report","Режим просмотра · скачивание отключено":"View mode · download disabled","Закрыть":"Close","Обзор":"Overview","Состав отчёта":"Report contents","Рекомендации":"Recommendations","Демонстрационный интерфейс показывает формат результата. Данные не относятся к реальному клиенту.":"The demo interface shows the deliverable format. The data does not belong to a real client.","Обсудить такой проект":"Discuss a similar project"});
  Object.assign(FULL_TRANSLATIONS,{"О нас":"About us","Аналитическое агентство Unitmetra":"Unitmetra analytics agency","Собираем команду аналитиков под задачу и отвечаем за понятный результат":"We assemble the right analytics team for the task and take responsibility for a clear result","Помогаем продавцам Wildberries и Ozon, малому бизнесу и компаниям с ML-задачами. Объединяем аналитику, Data Science и программную реализацию в одном проекте — без необходимости нанимать отдельную команду в штат.":"We help Wildberries and Ozon sellers, small businesses and companies with ML tasks. Analytics, Data Science and software delivery are combined in one project without hiring a separate in-house team.","Обсудить задачу":"Discuss the task","Посмотреть решения":"View solutions","Как устроена работа":"How delivery works","Unitmetra работает как агентство, а не как один универсальный исполнитель":"Unitmetra works as an agency, not as one universal freelancer","Подключаем специалистов в зависимости от задачи, а клиент получает единый план, сроки, коммуникацию и контроль качества.":"We involve specialists according to the task, while the client gets one plan, timeline, communication process and quality control.","Руководитель проекта":"Project lead","Фиксирует бизнес-задачу, результат, сроки и коммуникацию.":"Defines the business task, deliverable, timeline and communication.","Профильный аналитик":"Specialist analyst","Проверяет данные, выполняет расчёты и формирует выводы.":"Validates data, performs calculations and produces findings.","Data Science и разработка":"Data Science and development","Подключаются для прогнозов, Python, SQL, API и автоматизации.":"Join for forecasting, Python, SQL, API and automation.","Контроль качества":"Quality control","Проверяет цифры, логику и понятность рекомендаций.":"Reviews numbers, logic and clarity of recommendations.","Направления":"Areas","Решаем задачи от разового аудита до ML-системы":"We solve tasks from a one-off audit to a production ML system","Маркетплейсы":"Marketplaces","Прибыль по SKU, реклама, возвраты, логистика, остатки и прогноз поставок.":"SKU profit, advertising, returns, logistics, inventory and supply forecasting.","Услуги и пакеты →":"Services and packages →","Малый бизнес":"Small business","Продажи, расходы, клиенты, маркетинг и управленческий дашборд для собственника.":"Sales, expenses, customers, marketing and a management dashboard for the owner.","Машинное обучение":"Machine Learning","Прогноз спроса, покупки и оттока, сегментация, поиск аномалий и интеграция модели.":"Demand, purchase and churn forecasting, segmentation, anomaly detection and model integration.","Посмотреть ML-отчёт →":"View ML report →","Стандарт качества":"Quality standard","Что проверяем перед передачей результата":"What we review before delivery","Красивый график сам по себе не является аналитикой. Итог должен быть корректным, объяснимым и пригодным для решения конкретной задачи.":"A beautiful chart alone is not analytics. The result must be correct, explainable and suitable for a specific decision.","Полнота данных":"Data completeness","Проверяем источники, периоды, пропуски и дубликаты.":"We check sources, periods, missing values and duplicates.","Логика расчётов":"Calculation logic","Фиксируем формулы и сопоставляем показатели между источниками.":"We document formulas and reconcile metrics across sources.","Цена ошибки":"Cost of error","Выбираем метрики и пороги под реальное бизнес-решение.":"We select metrics and thresholds for the actual business decision.","Интерпретация":"Interpretation","Объясняем, почему получен результат и где его ограничения.":"We explain why the result was obtained and where its limitations are.","Практические действия":"Practical actions","Формируем приоритеты, а не оставляем клиента с набором диаграмм.":"We create priorities instead of leaving the client with a collection of charts.","Повторная проверка":"Second review","Исправляем обнаруженные ошибки и включаем два раунда правок.":"We correct detected errors and include two review rounds.","Безопасность данных":"Data security","Доступ только у команды проекта":"Access only for the project team","Данные не передаются третьим лицам. Публичные кейсы обезличиваются, крупные выгрузки передаются согласованным способом, файлы и доступы удаляются через 30 дней после завершения проекта.":"Data is not shared with third parties. Public cases are anonymised, large files are transferred via an agreed method, and files and access credentials are deleted 30 days after the project.","Два администратора":"Two administrators","Обезличивание кейсов":"Case anonymisation","API только при необходимости":"API only when needed","Удаление файлов через 30 дней":"Files deleted after 30 days","Принципы":"Principles","Какой образ работы мы строим":"How we work","Понятно":"Clear","Переводим расчёты и ML-метрики на язык решений собственника.":"We translate calculations and ML metrics into the language of owner decisions.","Честно":"Honest","Не обещаем гарантированную прибыль и не предлагаем ML без достаточных данных.":"We do not promise guaranteed profit or propose ML without enough data.","Технологично":"Technology-driven","Используем Python, SQL, API и автоматизацию там, где это действительно полезно.":"We use Python, SQL, API and automation where they create real value.","Ответственно":"Responsible","Согласуем состав результата до начала и проверяем его перед передачей.":"We agree the deliverable before starting and review it before handover.","Расскажите о задаче — предложим состав команды и формат работы":"Tell us about the task — we will propose the team and delivery format","На бесплатной диагностике определим, какие данные нужны, что вы получите и какой пакет подойдёт.":"During the free diagnostic we will define the required data, deliverables and suitable package.","Получить бесплатную диагностику":"Get a free diagnostic","Machine Learning, которое помогает бизнесу принимать решения":"Machine Learning that helps business make decisions","Команда Unitmetra превращает историю продаж и поведения клиентов в прогнозы, понятные сегменты и рабочие инструменты — таблицу, дашборд, Python/SQL-модуль или API.":"The Unitmetra team turns sales and customer-behaviour history into forecasts, clear segments and working tools: a table, dashboard, Python/SQL module or API.","Пример ML-отчёта · случайно сгенерированные данные":"ML report example · randomly generated data","Как модель помогает выбрать клиентов, которым стоит отправить предложение":"How a model helps select customers who should receive an offer","Ниже — интерактивный пример на 12 000 вымышленных клиентах интернет-магазина. Все цифры рассчитаны на синтетических данных и показывают формат результата, а не результат реального клиента.":"Below is an interactive example using 12,000 fictional e-commerce customers. All figures are calculated on synthetic data and demonstrate the deliverable format, not a real client result.","Прогноз покупки в течение 90 дней":"Purchase forecast within 90 days","Пример · данные случайные · без скачивания":"Example · random data · no download","Бизнес-вопрос":"Business question","Кому отправить персональное предложение, чтобы не тратить бюджет на всю базу?":"Who should receive a personalised offer so the budget is not spent on the whole customer base?","Ответ модели":"Model answer","Вероятность покупки для каждого клиента от 0% до 100%.":"Purchase probability for every customer from 0% to 100%.","Решение":"Decision","Выбрать порог и сформировать приоритетный список для коммуникации.":"Choose a threshold and create a priority contact list.","Клиентов в данных":"Customers in data","случайно сгенерированные записи":"randomly generated records","Проверочная выборка":"Test sample","на ней оценивали качество":"used to evaluate quality","Покупка в 90 дней":"Purchase within 90 days","базовая доля без модели":"base rate without a model","ROC-AUC модели":"Model ROC-AUC","хорошо разделяет вероятных покупателей":"separates likely buyers well","Что означает качество 0,85 простыми словами":"What a score of 0.85 means in plain language","Если случайно взять будущего покупателя и клиента без покупки, модель примерно в 85 случаях из 100 поставит будущего покупателя выше по вероятности. Это не обещание покупки каждому человеку, а инструмент для более точного выбора аудитории.":"If we randomly select a future buyer and a non-buyer, the model ranks the future buyer higher in about 85 out of 100 cases. This is not a purchase promise for every person; it is a tool for more accurate audience selection.","Без модели":"No model","случайный выбор клиентов":"random customer selection","Градиентный бустинг":"Gradient boosting","сильная модель, сложнее объяснять":"strong model, harder to explain","Выбрана логистическая регрессия":"Selected logistic regression","качество + понятная интерпретация":"quality + clear interpretation","Интерактивный выбор":"Interactive choice","Насколько строгим должен быть отбор клиентов?":"How strict should customer selection be?","Чем выше порог, тем меньше аудитория и выше доля покупателей внутри неё. Передвиньте ползунок.":"The higher the threshold, the smaller the audience and the higher the buyer share within it. Move the slider.","Минимальная вероятность покупки:":"Minimum purchase probability:","Больше охват":"More reach","Выше точность":"Higher precision","Связаться с клиентами":"Contact customers","из 3 000":"out of 3,000","Покупателей внутри":"Buyers within selection","в синтетическом тесте":"in the synthetic test","Доля покупателей":"Buyer share","вместо базовых 26,8%":"instead of the 26.8% base rate","Найдено будущих покупателей":"Future buyers found","от всех покупателей выборки":"of all buyers in the sample","Сегментация":"Segmentation","Клиенты по готовности к покупке":"Customers by purchase readiness","3 группы":"3 groups","Высокая вероятность":"High probability","Средняя вероятность":"Medium probability","Низкая вероятность":"Low probability","Модель не просто говорит «купит / не купит». Она позволяет выбрать разные сценарии для разных групп.":"The model does not simply say “will buy / will not buy”. It enables different actions for different groups.","Что сильнее всего влияет на прогноз":"What influences the forecast most","понятно бизнесу":"clear for business","Давность последней покупки":"Recency of last purchase","чем меньше дней, тем выше вероятность":"fewer days means a higher probability","Добавления в корзину":"Cart additions","сигнал готовности к покупке":"signal of purchase readiness","Открытия email":"Email opens","реакция на коммуникации":"response to communications","Сумма прошлых покупок":"Historical purchase value","ценность и привычка покупать":"value and buying habit","Количество прошлых покупок":"Number of previous purchases","лояльность клиента":"customer loyalty","Рабочий результат":"Working output","Пример таблицы, которую получает бизнес":"Example table delivered to the business","можно передать в CRM":"can be sent to a CRM","Клиент":"Customer","Вероятность":"Probability","Сегмент":"Segment","Дней без покупки":"Days since purchase","Покупок ранее":"Previous purchases","Действие":"Action","Высокая":"High","Средняя":"Medium","Низкая":"Low","Персональное предложение":"Personalised offer","Тест оффера":"Offer test","Не увеличивать частоту":"Do not increase frequency","Таблица прогнозов":"Prediction table","Вероятность, сегмент и рекомендуемое действие по каждому объекту.":"Probability, segment and recommended action for every object.","Понятный отчёт":"Clear report","Метрики без перегруза, ограничения модели и бизнес-выводы.":"Metrics without overload, model limitations and business findings.","Код и логика":"Code and logic","Notebook или Python/SQL-модуль с воспроизводимым расчётом.":"Notebook or Python/SQL module with reproducible calculations.","План внедрения":"Implementation plan","Как использовать прогноз, обновлять его и измерять реальный эффект.":"How to use and refresh the forecast and measure real impact.","Важно:":"Important:","данные в примере случайно сгенерированы, имена клиентов вымышлены. Показатели демонстрируют формат анализа. Для реального проекта качество и полезность модели проверяются только на данных конкретного бизнеса.":"the data in this example is randomly generated and customer names are fictional. Metrics demonstrate the analysis format. For a real project, model quality and usefulness are evaluated only on the specific business data.","Что получает заказчик":"What the client receives","Не «модель ради модели», а рабочий бизнес-инструмент":"Not a model for its own sake, but a working business tool","Проект выполняет согласованная команда: Data Scientist, аналитик и специалист по программной реализации. Результат проходит проверку качества перед передачей.":"The project is delivered by a coordinated team: a Data Scientist, analyst and software implementation specialist. The result is quality-reviewed before handover.","Постановка задачи":"Problem definition","Определяем решение, которое бизнес будет принимать по прогнозу.":"We define the decision the business will make using the forecast.","Модель и проверка":"Model and validation","Сравниваем подходы, метрики и стоимость разных ошибок.":"We compare approaches, metrics and the cost of different errors.","Понятный результат":"Clear result","Таблица, отчёт, интерпретация и рекомендации для пользователей.":"A table, report, interpretation and recommendations for users.","Запуск":"Launch","При необходимости создаём Python/SQL-модуль, API или дашборд.":"If needed, we build a Python/SQL module, API or dashboard."});
  const html=document.documentElement;const KEY='unitmetra-lang';let lang=storage.get(KEY)||'ru';
  // Add Machine Learning to the main navigation on every page.
  document.querySelectorAll('.nav').forEach(mainNav=>{
    if(mainNav.querySelector('a[href="machine-learning.html"]'))return;
    const mlLink=document.createElement('a');
    mlLink.href='machine-learning.html';
    mlLink.dataset.i18n='nav.ml';
    mlLink.textContent='ML';
    mlLink.title='Машинное обучение';
    mlLink.setAttribute('aria-label','Машинное обучение');
    const currentPage=(location.pathname.split('/').pop()||'index.html').toLowerCase();
    if(currentPage==='machine-learning.html')mlLink.classList.add('active');
    const casesLink=[...mainNav.querySelectorAll('a')].find(a=>a.getAttribute('href')==='cases.html');
    if(casesLink)casesLink.insertAdjacentElement('afterend',mlLink);else mainNav.appendChild(mlLink);
  });
  function setLang(next){
    if(lang==='en'&&next==='ru')applyFullTranslation(false);
    lang=next;storage.set(KEY,lang);html.lang=lang;
    document.querySelectorAll('[data-service-finder]').forEach(block=>block._updateFinder?.());
    document.querySelectorAll('[data-i18n]').forEach(el=>{const t=translations[el.dataset.i18n];if(t)el.innerHTML=t[lang==='ru'?0:1]});
    document.querySelectorAll('[data-lang]').forEach(b=>b.classList.toggle('active',b.dataset.lang===lang));
    document.querySelectorAll('[data-title-ru]').forEach(el=>{document.title=lang==='ru'?el.dataset.titleRu:el.dataset.titleEn});
    document.querySelectorAll('[data-content-ru]').forEach(el=>{el.setAttribute('content',lang==='ru'?el.dataset.contentRu:el.dataset.contentEn)});
    if(lang==='en')applyFullTranslation(true);
  }
  document.querySelectorAll('[data-lang]').forEach(b=>b.addEventListener('click',()=>setLang(b.dataset.lang)));
  const _translationObserver=new MutationObserver(records=>{if(lang!=='en')return;records.forEach(r=>r.addedNodes.forEach(n=>_translateNode(n,true)))});
  _translationObserver.observe(document.documentElement,{subtree:true,childList:true});

  const menu=document.querySelector('.mobile-toggle'),nav=document.querySelector('.nav');if(menu&&nav){menu.addEventListener('click',()=>nav.classList.toggle('open'));nav.querySelectorAll('a').forEach(a=>a.addEventListener('click',()=>nav.classList.remove('open')))}
  const obs=new IntersectionObserver(es=>es.forEach(e=>{if(e.isIntersecting){e.target.classList.add('visible');obs.unobserve(e.target)}}),{threshold:.08});document.querySelectorAll('[data-reveal]').forEach(el=>obs.observe(el));
